module gradient_descent_optimizer(  
    input [15:0] current_weights,  
    input [15:0] learning_rate,  
    input [15:0] gradient,  
    output [15:0] updated_weights  
);  
    wire __updated_weights_tmp = current_weights - (learning_rate * gradient);
    assign updated_weights = __updated_weights_tmp;  
endmodule
